!function(){"use strict";window.CJ=window.CJ||{},CJ.validate={email:function(t){return!(!t||"string"!=typeof t)&&/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(t.trim())},password:function(t){return"string"==typeof t&&t.length>=6},futureDate:function(t){if(!t)return!1;var e=new Date(t);return!isNaN(e.getTime())&&e>new Date},coordinates:function(t,e){var n=parseFloat(t),r=parseFloat(e);return Number.isFinite(n)&&Number.isFinite(r)&&n>=-90&&n<=90&&r>=-180&&r<=180},sanitizeHTML:function(t){return String(t||"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#39;")},maxLength:function(t,e){return!t||String(t).length<=e},truncate:function(t,e){if(!t)return"";var n=String(t);return n.length>e?n.substring(0,e):n},phone:function(t){return!t||/^\d{6,15}$/.test(t.replace(/[\s\-\+\(\)]/g,""))},url:function(t){if(!t)return!0;try{return new URL(t),!0}catch(t){return!1}}},window.CJ.validate=CJ.validate}();